import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,b as t}from"./app-291b7530.js";const e={},p=t(`<h2 id="问题背景" tabindex="-1"><a class="header-anchor" href="#问题背景" aria-hidden="true">#</a> 问题背景</h2><p>积分商城项目：简单来说就是客户在银行存钱，会产生相应的积分，然后客户可以在积分商城里面使用积分购物，由于客户的积分按照每年清空，并且积分商城会在一些节假日有活动，虽然平常使用的人数并不多，但是每逢节假日或者年末，积分商城的访问量就会增多，因此整个项目总体还是直接采用比较流行的微服务架构，并且需要考虑高并发</p><p>商品三级分类功能（eg：手机&gt;手机配件&gt;手机充电器），三级分类这种数据通常不怎么会变化，但是客户基本上访问商城首页的时候，都会发起该请求，所以考虑到将该部分数据放入redis中，以此来减轻系统压力</p><h2 id="复现条件" tabindex="-1"><a class="header-anchor" href="#复现条件" aria-hidden="true">#</a> 复现条件</h2><ol><li>Springboot 2.x整合redis</li><li>设置vm参数<code>-Xmx100m</code>，设置jvm最大堆内存只有100m</li><li>jmeter压测，并发200</li></ol><p>在进行压力测试的时候，发现总会报错<code>OutOfDirectMemoryError</code>，详细错误信息：</p><p><code>lettuce.core.RedisException: io.netty.util.internal.OutOfDirectMemoryError: failed to allocate 46137344 byte(s) of direct memory (used: 58720256, max: 100663296</code></p><h2 id="源码分析" tabindex="-1"><a class="header-anchor" href="#源码分析" aria-hidden="true">#</a> 源码分析</h2><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">class</span> <span class="token class-name">PlatformDependent</span> <span class="token punctuation">{</span>
    <span class="token comment">// 直接内存大小，可通过 “-Dio.netty.maxDirectMemory”参数设置。</span>
    <span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">long</span> <span class="token constant">DIRECT_MEMORY_LIMIT</span><span class="token punctuation">;</span>

    <span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">long</span> <span class="token constant">MAX_DIRECT_MEMORY</span> <span class="token operator">=</span> <span class="token function">maxDirectMemory0</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">static</span> <span class="token punctuation">{</span>
        <span class="token comment">// 其他赋值操作，略</span>

        <span class="token comment">// 给 直接内存大小赋值，如果有设置 &quot;-Dio.netty.maxDirectMemory&quot; 参数，则使用用户设置的，如果没有则使用默认的</span>
        logger<span class="token punctuation">.</span><span class="token function">debug</span><span class="token punctuation">(</span><span class="token string">&quot;-Dio.netty.maxDirectMemory: {} bytes&quot;</span><span class="token punctuation">,</span> maxDirectMemory<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token constant">DIRECT_MEMORY_LIMIT</span> <span class="token operator">=</span> maxDirectMemory <span class="token operator">&gt;=</span> <span class="token number">1</span> <span class="token operator">?</span> maxDirectMemory <span class="token operator">:</span> <span class="token constant">MAX_DIRECT_MEMORY</span><span class="token punctuation">;</span>

    <span class="token punctuation">}</span>

    <span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">incrementMemoryCounter</span><span class="token punctuation">(</span><span class="token keyword">int</span> capacity<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token constant">DIRECT_MEMORY_COUNTER</span> <span class="token operator">!=</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">long</span> newUsedMemory <span class="token operator">=</span> <span class="token constant">DIRECT_MEMORY_COUNTER</span><span class="token punctuation">.</span><span class="token function">addAndGet</span><span class="token punctuation">(</span>capacity<span class="token punctuation">)</span><span class="token punctuation">;</span>

            <span class="token comment">//关键判断：如果 netty内部使用的内存大小 大于 “直接内存大小”的话，就抛出 &quot;OutOfDirectMemoryError&quot;异常。</span>
            <span class="token keyword">if</span> <span class="token punctuation">(</span>newUsedMemory <span class="token operator">&gt;</span> <span class="token constant">DIRECT_MEMORY_LIMIT</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                <span class="token constant">DIRECT_MEMORY_COUNTER</span><span class="token punctuation">.</span><span class="token function">addAndGet</span><span class="token punctuation">(</span><span class="token operator">-</span>capacity<span class="token punctuation">)</span><span class="token punctuation">;</span>
                <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">OutOfDirectMemoryError</span><span class="token punctuation">(</span><span class="token string">&quot;failed to allocate &quot;</span> <span class="token operator">+</span> capacity
                                                 <span class="token operator">+</span> <span class="token string">&quot; byte(s) of direct memory (used: &quot;</span> <span class="token operator">+</span> <span class="token punctuation">(</span>newUsedMemory <span class="token operator">-</span> capacity<span class="token punctuation">)</span>
                                                 <span class="token operator">+</span> <span class="token string">&quot;, max: &quot;</span> <span class="token operator">+</span> <span class="token constant">DIRECT_MEMORY_LIMIT</span> <span class="token operator">+</span> <span class="token char">&#39;)&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>    

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="原因总结" tabindex="-1"><a class="header-anchor" href="#原因总结" aria-hidden="true">#</a> 原因总结</h2><ol><li><p><code>Springboot 2.x</code> 以后默认使用 <code>Lettuce</code>作为操作 redis 的客户端。它是使用 <code>netty</code> 进行网络通信的。</p></li><li><p>从<code>spring-boot-starter-data-redis(2.1.14.RELEASE)</code> 依赖可以看出内置使用的确实是 Lettuce 客户端，分析源码得知，lettuce 使用的netty框架，引用的netty包<code>netty-common-4.1.49.Final.jar</code>里面有一个<code>PlatformDependent.java</code>类 ，底层有个<code>-Dio.netty.maxDirectMemory</code> 参数，会自己校验堆外直接内存是否大于当前服务可使用的内存，如果大于则抛出 <code>OutOfDirectMemoryError</code>。显然，这是Lettuce/Netty（<code>netty-common-4.1.49.Final.jar</code>）的bug导致的</p></li></ol><h2 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h2><p>不能使用<code>-Dio.netty.maxDirectMemory</code> 只调大堆外内存，这只能延迟bug出现的时机，不能完全解决该问题，想完全解决，有两个方案：</p><ol><li>升级Lettuce到更新的版本(2.3.2已解决)</li><li>排除Lettuce，改用Jedis</li></ol><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token comment">&lt;!-- 引入 redis 依赖--&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-starter-data-redis<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- 排除 lettuce 客戶端--&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>exclusions</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>exclusion</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>io.lettuce<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>lettuce-core<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>exclusion</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>exclusions</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>

<span class="token comment">&lt;!-- 引入jedis客戶端--&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>redis.clients<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>jedis<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,15),o=[p];function c(l,i){return s(),a("div",null,o)}const d=n(e,[["render",c],["__file","Redis报错OutOfDirectMemoryError.html.vue"]]);export{d as default};
